import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Assume formatDate is exported from './dateUtils'
import { formatDate } from './dateUtils';

describe('formatDate', () => {
  // Happy path: valid ISO string
  it('should handle happy path: return formatted date for a valid ISO string', () => {
    const iso = '2024-05-25T14:30:00Z';
    const result = formatDate(iso);
    expect(result).toBe('2024-05-25');
  });

  // Edge case: year 0 and leap year handling
  it('should handle edge case: correctly format a leap day ISO string', () => {
    const isoLeap = '2020-02-29T00:00:00Z';
    const result = formatDate(isoLeap);
    expect(result).toBe('2020-02-29');
    const isoEdge = '0001-01-01T12:00:00Z';
    const resultEdge = formatDate(isoEdge);
    expect(resultEdge).toBe('0001-01-01');
  });

  // Null / empty inputs
  it('should handle null/empty: return empty string for null, undefined, empty string or 0', () => {
    expect(formatDate(null as any)).toBe('');
    expect(formatDate(undefined as any)).toBe('');
    expect(formatDate('' as any)).toBe('');
    expect(formatDate(0 as any)).toBe('');
  });
});

