import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Assuming the function is exported from a module named './utils'
import { truncateContent } from './utils';

describe('truncateContent', () => {
  it('should handle happy path: truncate when content exceeds maxLength', () => {
    const longText = 'a'.repeat(100);
    const result = truncateContent(longText, 80);
    // Expect the result to be exactly 80 characters long (no ellipsis added in this simple implementation)
    expect(result.length).toBe(80);
    expect(result).toBe('a'.repeat(80));
  });

  it('should handle edge case: content length exactly equals maxLength', () => {
    const exactText = 'b'.repeat(80);
    const result = truncateContent(exactText, 80);
    // Should return the original string unchanged
    expect(result).toBe(exactText);
    expect(result.length).toBe(80);
  });

  it('should handle null/empty inputs gracefully', () => {
    // Null input
    // @ts-ignore – deliberately passing null to test handling
    expect(() => truncateContent(null, 50)).not.toThrow();
    // Undefined input
    // @ts-ignore – deliberately passing undefined to test handling
    expect(() => truncateContent(undefined, 50)).not.toThrow();
    // Empty string
    expect(truncateContent('', 50)).toBe('');
    // Zero maxLength
    const text = 'sample';
    expect(truncateContent(text, 0)).toBe('');
  });
});

